$templateCache.put("market-value.html","<div id=\"pageErrors\" class=\"flash govuk-error-summary\" role=\"group\" aria-labelledby=\"errorSummary\" tabindex=\"-1\" data-module=\"govuk-error-summary\">\n    <h2 class=\"govuk-error-summary__title\" id=\"errorSummary\">There is a problem</h2>\n    <div class=\"govuk-error-summary__body\">\n        <ul class=\"govuk-list govuk-error-summary__list\">\n            <li data-ng-if=\"state.hasError(\'paySDLT\')\"><a id=\"paySDLTPageErrMsg\" href=\"javascript:return false\" onclick=\"return false;\" data-ng-click=\"jumpTo(\'paySDLTUpfront\')\">{{state.validationMessage(\'paySDLT\')}}</a></li>\n            <li data-ng-if=\"state.hasError(\'marketValue\')\"><a id=\"marketValuePageErrMsg\" href=\"javascript:return false\" onclick=\"return false;\" data-ng-click=\"jumpTo(\'marketPropValue\')\">{{state.validationMessage(\'marketValue\')}}</a></li>\n        </ul>\n    </div>\n</div>\n\n<form name=\"marketValue\" class=\"form\">\n\n    <div class=\"govuk-form-group\" ng-class=\"{\'govuk-form-group--error\': state.hasError(\'paySDLT\')}\">\n        <fieldset class=\"govuk-fieldset\" role=\"group\">\n            <legend class=\"govuk-fieldset__legend govuk-fieldset__legend--l\">\n                <span class=\"govuk-caption-l\">{{title}}</span>\n                <h1 id=\"marketValue\" class=\"govuk-fieldset__heading\">\n                    Do you want to pay SDLT on the market value or only on the percentage of the property you are buying?\n                </h1>\n            </legend>\n            <span id=\"paySDLTErrMsg\" class=\"govuk-error-message\" data-ng-if=\"state.hasError(\'paySDLT\')\">\n                <span class=\"govuk-visually-hidden\">Error:</span> {{state.validationMessage(\'paySDLT\')}}\n            </span>\n            <div class=\"govuk-hint\" id=\"marketValue-hint\">You can choose to pay SDLT on the market value of the property. This is known as a ‘market value election’.</div>\n\n                <details class=\"govuk-details\" data-module=\"govuk-details\">\n                    <summary class=\"govuk-details__summary\" data-ng-click=\"toggleHelp(\'marketValue\')\"><span class=\"govuk-details__summary-text\">How does this work?</span></summary>\n                    <div class=\"govuk-details__text\" data-ng-if=\"displayHelp(\'marketValue\')\">\n                        <p class=\"govuk-body\"><a class=\"govuk-link\" id=\"first-time-buyers\" href=\"https://www.gov.uk/guidance/stamp-duty-land-tax-relief-for-land-or-property-transactions#first-time-buyers-relief\" title=\"opens in a new window\" rel=\"external\" target=\"_blank\">First Time Buyers Relief</a>\n                            will be applied to the SDLT on:\n                        </p>\n                        <ul class=\"govuk-list govuk-list--bullet\">\n                            <li>the market value of the property, or</li>\n                            <li>on the market value of the share of the property that is ultimately obtainable under the scheme</li>\n                        </ul>\n                        <p class=\"govuk-form-group\"> No further SDLT will be due if you purchase further shares in the property or acquire the property outright.</p>\n                    </div>\n                </details>\n\n            <p class=\"govuk-body\">Alternatively you can choose to pay SDLT on the amount you are paying for your initial purchase.</p>\n\n            <details class=\"govuk-details\" data-module=\"govuk-details\">\n                <summary class=\"govuk-details__summary\" data-ng-click=\"toggleHelp(\'initialValue\')\"><span class=\"govuk-details__summary-text\">How does this work?</span></summary>\n                <div class=\"govuk-details__text\" data-ng-if=\"displayHelp(\'initialValue\')\">\n                    <p class=\"govuk-body\">If you pay SDLT in stages, your First Time Buyers Relief will only be applied to the initial payment you make, including any rental payments.</p>\n                    <p class=\"govuk-body\">Further payments towards your property purchase made at a later stage may be liable to SDLT which could add\n                        up to a higher or lower total amount payable than the ‘market value election’ option.  First Time Buyers Relief is not available\n                        against those further payments.</p>\n                    <p class=\"govuk-body\">However if your total share in the property is never more than 80%, then you will not be liable for any further SDLT.</p>\n                </div>\n            </details>\n\n            <div class=\"govuk-radios__item\">\n                <input class=\"govuk-radios__input\" id=\"paySDLTUpfront\" data-ng-model=\"data.paySDLT\" name=\"paySDLT\" value=\"Using market value election\" type=\"radio\">\n                <label class=\"govuk-label govuk-radios__label\" for=\"paySDLTUpfront\">\n                    Pay SDLT up front by making a market value election\n                </label>\n            </div>\n            <div class=\"govuk-radios__item\">\n                <input class=\"govuk-radios__input\" id=\"paySDLTInStages\" data-ng-model=\"data.paySDLT\" name=\"paySDLT\" value=\"Stages\" type=\"radio\">\n                <label class=\"govuk-label govuk-radios__label\" for=\"paySDLTInStages\">\n                    Pay SDLT in stages\n                </label>\n            </div>\n        </fieldset>\n    </div>\n\n    <div data-ng-if=\"data.paySDLT === \'Using market value election\'\">\n        <div class=\"govuk-form-group\" ng-class=\"{\'govuk-form-group--error\': state.hasError(\'marketValue\')}\">\n            <fieldset class=\"govuk-fieldset\">\n                <span id=\"marketValueErrMsg\" class=\"govuk-error-message\" data-ng-if=\"state.hasError(\'marketValue\')\">\n                    <span class=\"govuk-visually-hidden\">Error:</span> {{state.validationMessage(\'marketValue\')}}\n                </span>\n\n                <div class=\"govuk-form-group\">\n                    <h2 class=\"govuk-label-wrapper\">\n                        <label class=\"govuk-label govuk-label--l\" for=\"marketPropValue\">\n                            Market value of the property you are buying\n                        </label>\n                    </h2>\n                    <div class=\"govuk-input__wrapper\">\n                        <div class=\"govuk-input__prefix\" aria-hidden=\"true\">£</div>\n                        <input class=\"govuk-input govuk-input--width-10\" id=\"marketPropValue\" data-ng-model=\"data.premium\" name=\"marketPropValue\" type=\"text\">\n                    </div>\n                </div>\n\n            </fieldset>\n        </div>\n    </div>\n    <div data-ng-if=\"data.paySDLT === \'Stages\'\">\n        <div class=\"govuk-form-group\" ng-class=\"{\'govuk-form-group--error\': state.hasError(\'marketValue\')}\">\n            <fieldset class=\"govuk-fieldset\">\n                <span id=\"stageValueErrMsg\" class=\"govuk-error-message\" data-ng-if=\"state.hasError(\'marketValue\')\">\n                    <span class=\"govuk-visually-hidden\">Error:</span> {{state.validationMessage(\'marketValue\')}}\n                </span>\n                <div class=\"govuk-form-group\">\n                    <h2 class=\"govuk-label-wrapper\">\n                        <label class=\"govuk-label govuk-label--l\" for=\"marketPropValue\">\n                            Price of initial share of the property\n                        </label>\n                    </h2>\n                    <div class=\"govuk-input__wrapper\">\n                        <div class=\"govuk-input__prefix\" aria-hidden=\"true\">£</div>\n                        <input class=\"govuk-input govuk-input--width-10\" id=\"marketPropValue\" data-ng-model=\"data.premium\" name=\"stagePropValue\" type=\"text\">\n                    </div>\n                </div>\n            </fieldset>\n        </div>\n    </div>\n\n    <div class=\"govuk-form-group\">\n        <button data-ng-click=\"submit()\" class=\"govuk-button\" data-module=\"govuk-button\" id=\"continue-button\" type=\"submit\">Continue</button>\n    </div>\n\n</form>\n");
